import React, { useState, useEffect, useRef } from 'react';
import { statsAPI } from '../utils/api';
import { Chart as ChartJS, CategoryScale, LinearScale, BarElement, LineElement, PointElement, Title, Tooltip, Filler, ArcElement } from 'chart.js';
import { Bar, Line, Doughnut } from 'react-chartjs-2';
ChartJS.register(CategoryScale, LinearScale, BarElement, LineElement, PointElement, Title, Tooltip, Filler, ArcElement);

function StatCard({ label, value, icon, color, sub, pulse }) {
  const colors = {
    blue:   { main: 'var(--accent-blue)',   bg: 'rgba(0,212,255,0.06)',   border: 'rgba(0,212,255,0.2)'   },
    cyan:   { main: 'var(--accent-cyan)',   bg: 'rgba(0,255,204,0.06)',   border: 'rgba(0,255,204,0.2)'   },
    green:  { main: 'var(--accent-green)',  bg: 'rgba(0,255,136,0.06)',   border: 'rgba(0,255,136,0.2)'   },
    amber:  { main: 'var(--accent-amber)',  bg: 'rgba(255,170,0,0.06)',   border: 'rgba(255,170,0,0.2)'   },
    red:    { main: 'var(--accent-red)',    bg: 'rgba(255,51,102,0.06)',   border: 'rgba(255,51,102,0.2)'   },
    purple: { main: 'var(--accent-purple)', bg: 'rgba(180,77,255,0.06)',  border: 'rgba(180,77,255,0.2)'  },
  };
  const c = colors[color] || colors.blue;
  return (
    <div style={{
      background: c.bg, border: `1px solid ${c.border}`,
      padding: '18px', position: 'relative', overflow: 'hidden',
      animation: 'slide-in-up 0.5s ease-out',
    }}>
      {/* Corner accent */}
      <div style={{ position: 'absolute', top: 0, right: 0, width: '40px', height: '40px', background: `radial-gradient(circle at top right, ${c.main}20, transparent 70%)` }} />
      <div style={{ position: 'absolute', top: '-1px', left: 0, right: 0, height: '1px', background: `linear-gradient(90deg, transparent, ${c.main}, transparent)` }} />

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '12px' }}>
        <span style={{ fontSize: '20px', color: c.main }}>{icon}</span>
        {pulse && <span style={{ width: '8px', height: '8px', borderRadius: '50%', background: c.main, animation: 'pulse-glow 1.5s infinite', display: 'block', boxShadow: `0 0 8px ${c.main}` }} />}
      </div>
      <div style={{ fontSize: '32px', fontWeight: '700', fontFamily: "'Space Mono', monospace", color: c.main, marginBottom: '4px', letterSpacing: '-0.02em' }}>
        {value ?? '—'}
      </div>
      <div style={{ fontSize: '12px', fontWeight: '600', color: 'var(--text-primary)', letterSpacing: '0.05em', textTransform: 'uppercase', marginBottom: '2px' }}>{label}</div>
      {sub && <div style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.08em' }}>{sub}</div>}
    </div>
  );
}

const CHART_BASE = {
  responsive: true, maintainAspectRatio: false,
  plugins: { legend: { display: false }, tooltip: {
    backgroundColor: 'rgba(4,8,16,0.95)', borderColor: 'rgba(0,212,255,0.3)', borderWidth: 1,
    titleFont: { family: "'Space Mono', monospace", size: 10 },
    bodyFont: { family: "'JetBrains Mono', monospace", size: 11 },
    titleColor: '#00d4ff', bodyColor: '#e8f4ff',
  }},
  scales: {
    x: { grid: { color: 'rgba(10,22,40,0.8)' }, ticks: { color: '#1e3a55', font: { family: "'JetBrains Mono', monospace", size: 9 } } },
    y: { grid: { color: 'rgba(10,22,40,0.8)' }, ticks: { color: '#1e3a55', font: { family: "'JetBrains Mono', monospace", size: 9 } }, beginAtZero: true },
  },
};

export default function DashboardPage({ liveEvents }) {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchStats = async () => {
    try { const r = await statsAPI.get(); setStats(r.data); } catch {}
    setLoading(false);
  };

  useEffect(() => { fetchStats(); const i = setInterval(fetchStats, 15000); return () => clearInterval(i); }, []);
  useEffect(() => { if (liveEvents?.length) fetchStats(); }, [liveEvents]);

  const act = stats?.activity_7d || [];
  const labels = act.map(d => d.day?.slice(5) || '');
  const vals   = act.map(d => d.count);

  const barData = {
    labels,
    datasets: [{ data: vals, backgroundColor: 'rgba(0,212,255,0.15)', borderColor: 'var(--accent-blue)', borderWidth: 1.5, borderRadius: 2, hoverBackgroundColor: 'rgba(0,212,255,0.3)' }],
  };
  const lineData = {
    labels,
    datasets: [{ data: vals, borderColor: 'var(--accent-cyan)', backgroundColor: 'rgba(0,255,204,0.05)', fill: true, tension: 0.4, pointBackgroundColor: 'var(--accent-cyan)', pointRadius: 3, borderWidth: 2 }],
  };
  const doughnutData = {
    labels: ['Safe', 'Medium', 'High', 'Critical'],
    datasets: [{ data: [
      stats ? (stats.total_devices - stats.suspicious_devices) : 0,
      stats ? Math.floor(stats.suspicious_devices * 0.5) : 0,
      stats ? Math.ceil(stats.suspicious_devices * 0.3) : 0,
      stats ? Math.ceil(stats.suspicious_devices * 0.2) : 0,
    ], backgroundColor: ['rgba(0,255,136,0.7)', 'rgba(255,170,0,0.7)', 'rgba(255,102,0,0.7)', 'rgba(255,51,102,0.7)'], borderWidth: 0 }],
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--text-dim)', letterSpacing: '0.2em', marginBottom: '4px' }}>
            MODULE // OVW-001
          </div>
          <h1 style={{ fontSize: '22px', fontWeight: '700', color: 'var(--text-primary)', letterSpacing: '0.03em' }}>
            Security Overview
          </h1>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: '8px',
          background: 'rgba(0,255,136,0.05)', border: '1px solid rgba(0,255,136,0.2)',
          padding: '6px 14px', fontSize: '11px', fontFamily: "'Space Mono', monospace",
          color: 'var(--accent-green)', letterSpacing: '0.1em',
        }}>
          <span className="status-dot online" />
          LIVE MONITORING
        </div>
      </div>

      {loading ? (
        <div style={{ display: 'flex', justifyContent: 'center', padding: '60px' }}>
          <div style={{ width: '40px', height: '40px', border: '2px solid var(--border-dim)', borderTop: '2px solid var(--accent-blue)', borderRadius: '50%', animation: 'spin 0.8s linear infinite' }} />
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
      ) : (<>
        {/* Stat cards */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(170px, 1fr))', gap: '14px' }}>
          <StatCard label="Endpoints"      value={stats?.total_endpoints}        icon="⬢" color="blue"   sub={`${stats?.online_endpoints || 0} online`} pulse />
          <StatCard label="Devices Logged" value={stats?.total_devices}          icon="◈" color="cyan"   sub="All time" />
          <StatCard label="Threats"        value={stats?.suspicious_devices}     icon="⚠" color="amber"  sub="High + Critical" pulse={stats?.suspicious_devices > 0} />
          <StatCard label="Alerts"         value={stats?.unacknowledged_alerts}  icon="⬡" color="red"    sub={`${stats?.total_alerts || 0} total`} pulse={stats?.unacknowledged_alerts > 0} />
        </div>

        {/* Charts row */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 200px', gap: '14px' }}>
          {/* Bar chart */}
          <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', padding: '18px', position: 'relative' }}>
            <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: 'linear-gradient(90deg, var(--accent-blue), transparent)' }} />
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '16px' }}>
              <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--accent-blue)', letterSpacing: '0.15em' }}>DEVICE ACTIVITY // 7D</span>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)' }}>BAR</span>
            </div>
            <div style={{ height: '140px' }}><Bar data={barData} options={CHART_BASE} /></div>
          </div>

          {/* Line chart */}
          <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', padding: '18px', position: 'relative' }}>
            <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: 'linear-gradient(90deg, var(--accent-cyan), transparent)' }} />
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '16px' }}>
              <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--accent-cyan)', letterSpacing: '0.15em' }}>ACTIVITY TREND</span>
              <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)' }}>LINE</span>
            </div>
            <div style={{ height: '140px' }}><Line data={lineData} options={CHART_BASE} /></div>
          </div>

          {/* Doughnut */}
          <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', padding: '18px', position: 'relative' }}>
            <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: 'linear-gradient(90deg, var(--accent-purple), transparent)' }} />
            <div style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--accent-purple)', letterSpacing: '0.15em', marginBottom: '16px' }}>RISK SPLIT</div>
            <div style={{ height: '100px' }}>
              <Doughnut data={doughnutData} options={{ ...CHART_BASE, cutout: '65%', scales: undefined }} />
            </div>
            <div style={{ marginTop: '10px', display: 'flex', flexDirection: 'column', gap: '3px' }}>
              {[['var(--accent-green)', 'Safe'], ['var(--accent-amber)', 'Medium'], ['#ff6600', 'High'], ['var(--accent-red)', 'Critical']].map(([c, l]) => (
                <div key={l} style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
                  <span style={{ width: '6px', height: '6px', borderRadius: '50%', background: c, display: 'inline-block' }} />
                  <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-dim)' }}>{l}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Live event feed */}
        <div style={{ background: 'var(--bg-panel)', border: '1px solid var(--border-dim)', position: 'relative' }}>
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: '1px', background: 'linear-gradient(90deg, var(--accent-green), transparent)' }} />
          <div style={{ padding: '14px 18px', borderBottom: '1px solid var(--border-dim)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span className="status-dot online" />
              <span style={{ fontFamily: "'Space Mono', monospace", fontSize: '9px', color: 'var(--accent-green)', letterSpacing: '0.15em' }}>LIVE EVENT FEED</span>
            </div>
            <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)' }}>{liveEvents?.length || 0} EVENTS THIS SESSION</span>
          </div>
          <div style={{ padding: '0', maxHeight: '220px', overflowY: 'auto' }}>
            {!liveEvents?.length ? (
              <div style={{ padding: '40px', textAlign: 'center', color: 'var(--text-muted)', fontFamily: "'JetBrains Mono', monospace", fontSize: '11px' }}>
                AWAITING TELEMETRY... INSERT USB DEVICE ON ENDPOINT
              </div>
            ) : [...liveEvents].reverse().slice(0, 20).map((ev, i) => (
              <div key={i} className="animate-slide-in-right" style={{
                display: 'flex', alignItems: 'center', gap: '14px',
                padding: '10px 18px', borderBottom: '1px solid rgba(10,22,40,0.8)',
                transition: 'background 0.15s',
              }}
                onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-hover)'}
                onMouseLeave={e => e.currentTarget.style.background = 'transparent'}
              >
                <span className={`status-dot ${ev.risk_level === 'critical' ? 'alert' : ev.risk_level === 'high' ? 'warning' : 'online'}`} />
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '12px', color: 'var(--text-primary)', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{ev.device_name}</span>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '10px', color: 'var(--accent-blue)' }}>{ev.hostname}</span>
                <span style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: '9px', color: 'var(--text-muted)' }}>{ev.timestamp?.slice(11,19) || '--:--:--'}</span>
              </div>
            ))}
          </div>
        </div>
      </>)}
    </div>
  );
}
